#include "heavy/Builtins.h"
#include "heavy/Context.h"
#include "heavy/Mangle.h"
#include "heavy/OpGen.h"
#include "llvm/ADT/DenseMap.h"
#include "llvm/ADT/ScopedHashTable.h"
#include "llvm/Support/Casting.h"
#include <memory>
#include <stack>

namespace heavy {

class OpEvalImpl {
  using BlockItrTy = mlir::Block::iterator;
  using ValueMapTy = llvm::ScopedHashTable<mlir::Value, heavy::Value>;
  using ValueMapScope = typename ValueMapTy::ScopeTy;

  heavy::Context& Context;
  ValueMapTy ValueMap;

  void setValue(mlir::Value M, heavy::Value H) {
    assert(M && "must be set to a valid value");
    assert(H && "must be set to a valid value");
    ValueMap.insert(M, H);
  }

  void setValueParentScope(mlir::Value M, heavy::Value H) {
    assert(M && "must be set to a valid value");
    assert(H && "must be set to a valid value");
    ValueMapScope* CurScope = ValueMap.getCurScope();
    assert(CurScope && "expecting a scope");
    ValueMapScope* ParentScope = CurScope->getParentScope();
    assert(ParentScope && "expecting parent scope");
    ValueMap.insertIntoScope(ParentScope, M, H);
  }

  heavy::Value getBindingOrValue(mlir::Value M) {
    assert(M && "lookup requires a valid value");
    heavy::Value V = ValueMap.lookup(M);
    if (!V && (M.getDefiningOp<UndefinedOp>() ||
               M.getDefiningOp<SetOp>())) {
      return Context.CreateUndefined();
    }

    if (!V) {
      if (auto G = M.getDefiningOp<GlobalOp>()) {
        if (G.isExternal()) {
          heavy::Value Val = Context.GetKnownValue(G.getSymName());
          setValue(M, Val);
          return Val;
        }
      }
      if (auto G = M.getDefiningOp<GlobalSyntaxOp>()) {
        if (G.isExternal()) {
          heavy::Value Val = Context.GetKnownValue(G.getSymName());
          setValue(M, Val);
          return Val;
        }
      }
    }

    // failure here could mean failure to capture in a closure
    assert(V && "getValue requires a value in the table");

    return V;
  }

  heavy::Value getValue(mlir::Value M) {
    heavy::Value V = getBindingOrValue(M);
    if (Binding* B = dyn_cast<Binding>(V)) {
      V = B->getValue();
    }
    return V;
  }

  static heavy::SourceLocation getSourceLocation(mlir::Location Loc) {
    return heavy::SourceLocation(mlir::OpaqueLoc
      ::getUnderlyingLocationOrNull<heavy::SourceLocationEncoding*>(Loc));
  }

public:
  OpEvalImpl(heavy::Context& C)
    : Context(C),
      ValueMap()
  { }

  // Prevent copy/move since we capture this in a few lambdas.
  OpEvalImpl(OpEvalImpl const&) = delete;

  void Eval(mlir::Operation* Op) {
    if (isa<GlobalOp, GlobalSyntaxOp, CommandOp, LoadModuleOp>(Op)) {
      Visit(Op);
      // "Calling the continuation" is handled during visitation.
    } else if (auto ModuleOp = dyn_cast<mlir::ModuleOp>(Op)) {
      auto& Ops = ModuleOp.getBody()->getOperations();
      // op_eval each top level operation.
      // Push the top level ops in reverse order
      for (auto i = Ops.rbegin(); i != Ops.rend(); ++i) {
        // Loading modules is ... special.
        if (auto LM = dyn_cast<LoadModuleOp>(&*i)) {
          // This handles all of the consecutive LoadModuleOps.
          Visit(LM, /*ShouldCont=*/false);
          // Skip the others.
          for (; i != Ops.rend() && isa<LoadModuleOp>(&*i); ++i);
          if (i == Ops.rend())
            break;
        }
        mlir::Operation* TL = &*i;
        auto G = dyn_cast<GlobalOp>(TL);
        // External GlobalOps are skipped.
        if ((G && !G.isExternal()) || isa<CommandOp, LoadModuleOp>(TL)) {
          Context.PushCont([](heavy::Context& C, ValueRefs) mutable {
            heavy::Value Op = C.getCapture(0);
            Value Args[] = {Op};
            C.Apply(HEAVY_BASE_VAR(op_eval), Args);
          }, CaptureList{TL});
        }
      }
      Context.Cont();
    } else {
      SetError(SourceLocation(), "op_eval expects a top level op");
    }
  }

private:
  // Push a single LoadModuleOp to the continuation stack.
  void PushLoadModuleOp(LoadModuleOp Op) {
    heavy::Symbol* ModuleName = Context.CreateSymbol(Op.getName());
    Context.PushCont([](heavy::Context& C, ValueRefs) {
      heavy::Symbol* ModuleName = cast<Symbol>(C.getCapture(0));
      C.PushCont([](heavy::Context& C, ValueRefs) {
        heavy::Symbol* ModuleName = cast<Symbol>(C.getCapture(0));
        C.InitModule(ModuleName);
      }, CaptureList{ModuleName});
      C.LoadModule(ModuleName);
    }, CaptureList{ModuleName});
  }

  BlockItrTy next(mlir::Operation* Op) {
    return ++BlockItrTy(Op);
  }

  template <typename Message, typename Irritants>
  BlockItrTy RaiseError(Message M, Irritants Irrs) {
    Context.RaiseError(M, Irrs);

    return BlockItrTy();
  }

  template <typename StringTy>
  BlockItrTy SetError(SourceLocation Loc, StringTy Str,
                      heavy::Value Irr = heavy::Undefined()) {
    Context.setLoc(Loc);
    Context.RaiseError(Str, Irr);

    return BlockItrTy();
  }

  BlockItrTy Visit(mlir::Operation* Op) {
         if (isa<BindingOp>(Op))      return Visit(cast<BindingOp>(Op));
    else if (isa<LiteralOp>(Op))      return Visit(cast<LiteralOp>(Op));
    else if (isa<ApplyOp>(Op))        return Visit(cast<ApplyOp>(Op));
    else if (isa<ContOp>(Op))         return Visit(cast<ContOp>(Op));
    else if (isa<GlobalOp>(Op))       return Visit(cast<GlobalOp>(Op));
    else if (isa<GlobalSyntaxOp>(Op)) return Visit(cast<GlobalSyntaxOp>(Op));
    else if (isa<LoadRefOp>(Op))      return Visit(cast<LoadRefOp>(Op));
    else if (isa<LoadGlobalOp>(Op))   return Visit(cast<LoadGlobalOp>(Op));
    else if (isa<LambdaOp>(Op))       return Visit(cast<LambdaOp>(Op));
    else if (isa<IfContOp>(Op))       return Visit(cast<IfContOp>(Op));
    else if (isa<ConsOp>(Op))         return Visit(cast<ConsOp>(Op));
    else if (isa<SpliceOp>(Op))       return Visit(cast<SpliceOp>(Op));
    else if (isa<SetOp>(Op))          return Visit(cast<SetOp>(Op));
    else if (isa<CommandOp>(Op))      return Visit(cast<CommandOp>(Op));
    else if (isa<PushContOp>(Op))     return Visit(cast<PushContOp>(Op));
    else if (isa<OpGenOp>(Op))        return Visit(cast<OpGenOp>(Op));
    else if (isa<FuncOp>(Op))         return next(Op); // skip functions
    else if (isa<SyntaxOp>(Op))       return Visit(cast<SyntaxOp>(Op));
    else if (isa<PatternOp>(Op))      return Visit(cast<PatternOp>(Op));
    else if (isa<MatchPairOp>(Op))    return Visit(cast<MatchPairOp>(Op));
    else if (isa<MatchTailOp>(Op))    return Visit(cast<MatchTailOp>(Op));
    else if (isa<MatchArgsOp>(Op))    return Visit(cast<MatchArgsOp>(Op));
    else if (isa<SubpatternOp>(Op))   return Visit(cast<SubpatternOp>(Op));
    else if (isa<ExpandPacksOp>(Op))  return Visit(cast<ExpandPacksOp>(Op));
    else if (isa<ResolveOp>(Op))      return Visit(cast<ResolveOp>(Op));
    else if (isa<MatchOp>(Op))        return Visit(cast<MatchOp>(Op));
    else if (isa<MatchIdOp>(Op))      return Visit(cast<MatchIdOp>(Op));
    else if (isa<RenameOp>(Op))       return Visit(cast<RenameOp>(Op));
    else if (isa<RenameGlobalOp>(Op)) return Visit(cast<RenameGlobalOp>(Op));
    else if (isa<RenameEnvOp>(Op))    return Visit(cast<RenameEnvOp>(Op));
    else if (isa<ToVectorOp>(Op))     return Visit(cast<ToVectorOp>(Op));
    else if (isa<VectorOp>(Op))       return Visit(cast<VectorOp>(Op));
    else if (isa<LoadModuleOp>(Op))   return Visit(cast<LoadModuleOp>(Op));
    else if (isa<SyntaxClosureOp>(Op))
      return Visit(cast<SyntaxClosureOp>(Op));
    else if (isa<SourceLocOp>(Op))    return Visit(cast<SourceLocOp>(Op));
    else if (UndefinedOp UndefOp = dyn_cast<UndefinedOp>(Op)) {
      setValue(UndefOp, Context.CreateUndefined());
      return next(Op);
    }
    else {
      Op->dump();
      llvm_unreachable("unknown operation");
      return BlockItrTy();
    }
  }

  void LoadArgs(mlir::Block& Body, ValueRefs Args) {
    // Associate values with BlockArguments
    // which will later get assigned to BindingOps (in code)

    // Drop the context argument.
    auto OpArgs = Body.getArguments().drop_front();

    assert(OpArgs.size() == Args.size()
        && "arity should be checked already");
    // OpArg[0] is always the context object
  }

  BlockItrTy CallFuncOp(heavy::FuncOp F, ValueRefs Args) {
    auto Scope = ValueMapScope(ValueMap);
    mlir::Block& Body = F.getBody().front();

    // Drop the context argument.
    auto OpArgs = Body.getArguments().drop_front();
    bool IsValidArity = true;
    if (OpArgs.empty() && !Args.empty())
      IsValidArity = false;
    if (!OpArgs.empty() && !isa<HeavyValueRefsTy>(OpArgs.front().getType())) {
      if (OpArgs.size() != Args.size()) {
        IsValidArity = false;
      } else {
        // Load the arguments.
        for (unsigned i = 0; i < Args.size(); ++i)
          setValue(OpArgs[i], Args[i]);
      }
    }

    if (!IsValidArity) {
      heavy::SourceLocation Loc = getSourceLocation(F.getLoc());
      return SetError(Loc, "invalid arity");
    }

    BlockItrTy Itr = Body.begin();
    while (Itr != BlockItrTy())
      Itr = Visit(&*Itr);

    // The terminator operation should have
    // called Context.Apply() or one of those
    return BlockItrTy();
  }

  // SetContValues
  //  - Loads the values for the results of an Op
  //  - Used by ContOp and ApplyOp (since ApplyOp is dynamic)
  //  - Checks arity
  void SetContValues(mlir::Operation* Op, ValueRefs ContValues) {
    auto Results = Op->getResults();
    assert((Results.empty() ||
           Results.size() == ContValues.size()) &&
        "continuation arity must match");

    for (unsigned i = 0; i < Results.size(); ++i)
      setValue(Results[i], ContValues[i]);
  }

  BlockItrTy Visit(ApplyOp Op) {
    heavy::SourceLocation Loc = getSourceLocation(Op.getLoc());
    Context.setLoc(Loc);

    heavy::Value Callee = getValue(Op.getFn());
    llvm::SmallVector<heavy::Value, 8> ArgResults;

    auto MArgs = Op.getArgs();  // MLIR Args.

    for (mlir::Value Arg : MArgs) {
      ArgResults.push_back(getValue(Arg));
    }

    Context.Apply(Callee, ArgResults);
    return BlockItrTy();
  }

  BlockItrTy Visit(BindingOp Op) {
    // create a Binding
    heavy::Value V = Op.getInput() ? getValue(Op.getInput())
                                   : Value(Undefined());
    heavy::Binding* B = Context.CreateBinding(V);
    setValue(Op.getResult(), B);
    return next(Op);
  }

  BlockItrTy Visit(ConsOp Op) {
    heavy::Value A = getValue(Op.getA());
    heavy::Value B = getValue(Op.getB());
    heavy::SourceLocation Loc = getSourceLocation(Op.getLoc());
    heavy::Pair* V = Context.CreatePairWithSource(A, B, Loc);
    setValue(Op.getResult(), V);
    return next(Op);
  }

  BlockItrTy Visit(ContOp Op) {
    auto ContArgs = Op.getArgs();
    llvm::SmallVector<heavy::Value, 1> ContValues(ContArgs.size(),
                                                  nullptr);
    for (unsigned i = 0; i < ContArgs.size(); ++i)
      ContValues[i] = getValue(ContArgs[i]);


    Context.Cont(ContValues);
    return BlockItrTy();
  }

  BlockItrTy Visit(IfContOp Op) {
    Value Input = getValue(Op.getInput());
    return Input.isTrue() ? Op.getThenRegion().front().begin() :
                            Op.getElseRegion().front().begin();
  }

  heavy::FuncOp lookupFunction(llvm::StringRef MangledName) {
    // Look up the function in the module where it is defined.
    // This walks the IR linearly.
    // Look only at modules within the Context ModuleOp.
    // (The IR refers to an extern global definition of the variable.
    //  ie not the function itself.)
    auto TopModuleOp = cast<mlir::ModuleOp>(Context.ModuleOp);
    llvm::StringRef ModuleName = Mangler::parseModulePrefix(MangledName);
    auto M = dyn_cast_or_null<mlir::ModuleOp>(
        TopModuleOp.lookupSymbol(ModuleName));
    heavy::FuncOp F;
    if (M)
      F = dyn_cast_or_null<heavy::FuncOp>(M.lookupSymbol(MangledName));
    if (!F) {
      String* ErrMsg = Context.CreateString(
          "undefined reference to function ", MangledName);
      ExternName* EN = Context.CreateExternName({}, MangledName);
      SetError(heavy::SourceLocation(), ErrMsg, Undefined(EN));
      return {};
    }
    return F;
  }

  auto createClosure(mlir::Operation* Op,
                     heavy::FuncOp FuncOp) {
    return [FuncOp](heavy::Context& C, ValueRefs Args) {
      C.OpEval->CallFuncOp(FuncOp, Args);
    };
  }

  auto createClosure(mlir::Operation* Op,
                     heavy::FuncOp FuncOp,
                     mlir::ValueRange CaptureVals,
                     llvm::SmallVectorImpl<heavy::Value>& Captures) {
    for (mlir::Value Val : CaptureVals) {
      Captures.push_back(getBindingOrValue(Val));
    }

    return createClosure(Op, FuncOp);
  }

  BlockItrTy Visit(LambdaOp Op) {
    llvm::SmallVector<heavy::Value, 8> Captures;
    heavy::FuncOp F = lookupFunction(Op.getName());
    if (!F) return {};
    auto CallFn = createClosure(Op, F, Op.getCaptures(), Captures);
    Lambda* L = Context.CreateLambda(CallFn, Captures);

    setValue(Op.getResult(), L);
    return next(Op);
  }

  BlockItrTy Visit(PushContOp Op) {
    llvm::SmallVector<heavy::Value, 8> Captures;
    heavy::FuncOp F = lookupFunction(Op.getName());
    if (!F) return {};
    auto CallFn = createClosure(Op, F, Op.getCaptures(), Captures);
    Context.PushCont(CallFn, Captures);

    return next(Op);
  }

  BlockItrTy Visit(SyntaxOp Op) {
    heavy::FuncOp F = lookupFunction(Op.getName());
    if (!F) return {};
    auto CallFn = createClosure(Op, F);
    Syntax* S = Context.CreateSyntax(CallFn);

    setValue(Op.getResult(), S);
    return next(Op);
  }

  BlockItrTy Visit(PatternOp Op) {
    return Op.getRegion().front().begin();
  }

  BlockItrTy Visit(LiteralOp Op) {
    // Map the IR value node to the run-time value
    heavy::Value V = Op.getInput().getValue(Context);
    setValue(Op.getResult(), V);
    return next(Op);
  }

  BlockItrTy Visit(LoadRefOp Op) {
    // Load from a ValueRefs object which is accessible
    // through the Context object.
    uint32_t Index = Op.getIndex();

    mlir::Type RefsType = Op.getValueRefs().getType();
    heavy::ValueRefs ValueRefs;

    if (isa<HeavyContextTy>(RefsType)) {
      // Assume we always use the current context object.
      auto* Callee = cast<Lambda>(Context.getCallee());
      ValueRefs = Callee->getCaptures();
    } else if (isa<HeavyValueRefsTy>(RefsType)) {
      ValueRefs = Context.getCallArgs();
    }

    // This is defensive for captures if the IR is ill-formed,
    // but bad continuation arity is a run-time error.
    if (Index >= ValueRefs.size()) {
      heavy::SourceLocation Loc = getSourceLocation(Op.getLoc());
      return SetError(Loc, "invalid arity for continuation");
    }

    heavy::Value Result = ValueRefs[Index];

    setValue(Op.getResult(), Result);
    return next(Op);
  }

  BlockItrTy Visit(LoadModuleOp Op, bool ShouldCont = true) {
    // We always get here on the last LoadModuleOp.
    // which is the last inserted LoadModuleOp.
    // We need to evaluate all consecutive LoadModuleOps in the proper order.

    // Push the LoadModuleOp.
    heavy::Symbol* ModuleName = Context.CreateSymbol(Op.getName());
    Context.PushCont([](heavy::Context& C, ValueRefs) {
      heavy::Symbol* ModuleName = cast<Symbol>(C.getCapture(0));
      C.PushCont([](heavy::Context& C, ValueRefs) {
        heavy::Symbol* ModuleName = cast<Symbol>(C.getCapture(0));
        C.InitModule(ModuleName);
      }, CaptureList{ModuleName});
      C.LoadModule(ModuleName);
    }, CaptureList{ModuleName});

    // Handle previous LoadModuleOps.
    mlir::Block* Block = Op->getBlock();
    assert(Block && "expecting parent block");
    BlockItrTy Itr(Op);
    if (Itr != Block->begin()) {
      --Itr;
      if (auto PrevLM = dyn_cast<LoadModuleOp>(&*Itr))
        Visit(PrevLM, /*IsFirst=*/false);
    }

    if (ShouldCont)
      Context.Cont();
    return BlockItrTy();
  }

  BlockItrTy Visit(LoadGlobalOp Op) {
    Value Val = Context.GetKnownValue(Op.getName());
    if (!Val) {
      heavy::SourceLocation Loc = getSourceLocation(Op.getLoc());
      ExternName* EN = Context.CreateExternName(Loc, Op.getName());
      Val = Undefined(EN);
    }
    setValue(Op, Val);
    return next(Op);
  }

  BlockItrTy Visit(GlobalOp Op) {
    // Skip external global ops.
    if (Op.isExternal())
      return BlockItrTy();

    Context.PushCont([Op](heavy::Context& C, ValueRefs Args) mutable {
      assert(Args.size() == 1 && "invalid continuation arity");
      assert(!isa<Syntax>(Args[0]) && "not expecting syntax in GlobalOp");
      // Mutable globals must be wrapped with a binding
      Value Result = C.CreateBinding(Args[0]);
      C.AddKnownAddress(Op.getSymName(), Result);
      C.Cont();
    }, ValueRefs());

    auto Scope = ValueMapScope(ValueMap);
    BlockItrTy Itr = Op.getInitializer().front().begin();
    while (Itr != BlockItrTy())
      Itr = Visit(&*Itr);

    return BlockItrTy();
  }

  BlockItrTy Visit(GlobalSyntaxOp Op) {
    // Skip external global ops.
    if (Op.isExternal())
      return BlockItrTy();

    // The syntax may already be initialized.
    if (Value Val = Context.GetKnownValue(Op.getSymName())) {
      if (!isa<heavy::Undefined>(Val)) {
        Context.Cont();
        return BlockItrTy();
      }
    }

    Context.PushCont([Op](heavy::Context& C, ValueRefs Args) mutable {
      assert(Args.size() == 1 && "invalid continuation arity");
      heavy::Value Result = Args[0];
      C.AddKnownAddress(Op.getSymName(), Result);
      C.Cont();
    }, ValueRefs());

    auto Scope = ValueMapScope(ValueMap);
    BlockItrTy Itr = Op.getInitializer().front().begin();
    while (Itr != BlockItrTy())
      Itr = Visit(&*Itr);

    return BlockItrTy();
  }

  BlockItrTy Visit(CommandOp Op) {
    auto Scope = ValueMapScope(ValueMap);
    BlockItrTy Itr = Op.getBody().front().begin();
    while (Itr != BlockItrTy())
      Itr = Visit(&*Itr);

    return BlockItrTy();
  }

  BlockItrTy Visit(SetOp Op) {
    Value RawValue = getBindingOrValue(Op.getBinding());
    heavy::Binding* B = dyn_cast<heavy::Binding>(RawValue);
    if (!B) {
      Context.RaiseError("invalid set operand: {}", RawValue);
      return BlockItrTy();
    }

    heavy::Value RHS = getValue(Op.getInput());
    B->setValue(RHS);
    return next(Op);
  }

  BlockItrTy Visit(ToVectorOp Op) {
    heavy::SourceLocation Loc = getSourceLocation(Op.getLoc());
    heavy::Value Input = getValue(Op.getInput());
    heavy::Vector* Vector = nullptr;

    if (isa<Empty>(Input)) {
      Vector = Context.CreateVector({});
    } else {
      if(!isa<Pair>(Input))
        return SetError(Loc, "should be a non-empty list", Input);

      llvm::SmallVector<heavy::Value, 8> Xs;
      heavy::Value Next = Input;
      while (heavy::Pair* P = dyn_cast<Pair>(Next)) {
        Xs.push_back(P->Car);
        Next = P->Cdr;
      }
      if (!isa<Empty>(Next))
        return SetError(Loc, "should be a proper list", Next);

      Vector = Context.CreateVector(Xs);
    }
    setValue(Op, Vector);
    return next(Op);
  }

  BlockItrTy Visit(VectorOp Op) {
    unsigned Size = Op.getArgs().size();
    heavy::Vector* Vector = Context.CreateVector(Size);
    auto Vals = Op.getArgs();
    for (unsigned I = 0; I < Size; ++I)
      Vector->get(I) = getValue(Vals[I]);

    setValue(Op, Vector);
    return next(Op);
  }

  BlockItrTy Visit(RenameEnvOp Op) {
    unsigned NumBindings = Op.getBindings().size();
    heavy::EnvFrame* EnvFrame = Context.CreateEnvFrame(NumBindings);
    llvm::MutableArrayRef<Binding*> Bindings = EnvFrame->getBindings();
    auto Vals = Op.getBindings();
    for (unsigned I = 0; I < NumBindings; ++I)
      Bindings[I] = cast<Binding>(getBindingOrValue(Vals[I]));

    // Add the local environment on top of EnvFrame.
    heavy::Value Env = getValue(Op.getEnv());
    heavy::EnvFrame* LocalEnvFrame = Context.GetLocalEnvFrame(Env);
    // EnvFrame is the tail.
    heavy::Value NewEnv = Context.CreatePair(LocalEnvFrame, EnvFrame);

    setValue(Op, NewEnv);
    return next(Op);
  }

  BlockItrTy Visit(SpliceOp Op) {
    heavy::SourceLocation Loc = getSourceLocation(Op.getLoc());
    heavy::Value LHS = getValue(Op.getA());
    heavy::Value RHS = getValue(Op.getB());

    // LHS must be list.
    if (!isa<heavy::Pair>(LHS) && !isa<heavy::Empty>(LHS)) {
      return SetError(Loc, "splicing operand expected list", LHS);
    }

    // A new list must be created
    // Dummy is the start point that is not part of the result
    // as it is not on the heap
    heavy::Pair Dummy = heavy::Pair(nullptr, nullptr);
    heavy::Pair* Dest = &Dummy;
    heavy::Value Temp = LHS;

    while (Pair* Cur = dyn_cast<heavy::Pair>(Temp)) {
      heavy::Pair* New = Context.CreatePair(Cur->Car);
      Dest->Cdr = New;
      Dest = New;
      Temp = Cur->Cdr;
    }
    Temp = RHS;
    while (Pair* Cur = dyn_cast<heavy::Pair>(Temp)) {
      heavy::Pair* New = Context.CreatePair(Cur->Car);
      Dest->Cdr = New;
      Dest = New;
      Temp = Cur->Cdr;
    }
    heavy::Value Result = Dummy.Cdr ? Dummy.Cdr : Empty{};
    setValue(Op, Result);
    return next(Op);
  }

  // A pattern failing to match results in going to the next pattern
  // or, in the case of a pack, it begins matching the rest of the list.
  BlockItrTy patternFail(mlir::Operation* Op, llvm::StringRef ErrMsg,
                         llvm::ArrayRef<heavy::Value> Irr) {
    assert((isa<MatchOp, MatchPairOp, MatchTailOp, MatchArgsOp,
                MatchIdOp, SubpatternOp>(Op)) &&
        "Operation must be a pattern matcher");

    mlir::Operation* ParentOp = Op->getParentOp();

    // If we are not pattern matching then treat the operation as an error.
    if (!isa<PatternOp, SubpatternOp>(ParentOp)) {
      if (ErrMsg.empty())
        ErrMsg = "pattern failed to match";
      Context.RaiseError(ErrMsg, Irr);
      return BlockItrTy();
    }

    // Use the SubPatternOp itself as the sentinel for pattern failure.
    if (auto SubpatternOp = dyn_cast<heavy::SubpatternOp>(ParentOp))
      return BlockItrTy(SubpatternOp);

    assert(isa<heavy::PatternOp>(ParentOp) && "expecting a PatternOp.");

    // Abort the current pattern's scope and move to the next operation.
    return next(ParentOp);
  }

  BlockItrTy Visit(MatchOp Op) {
    heavy::Value P = Op.getVal().getValue(Context);
    heavy::Value E = getValue(Op.getInput());
    heavy::EnvEntry Entry;
    if (isIdentifier(E) && isIdentifier(P)) {
      // If the symbol is in the environment we can skip
      // because it will not match a literal.
      heavy::EnvEntry EntryE = Context.Lookup(E);
      heavy::EnvEntry EntryP = Context.Lookup(P);
      if (EntryE && EntryP && EntryE.Value == EntryP.Value)
        return next(Op);
      else if (EntryE || EntryP)
        return patternFail(Op,
            "expecting identifier with identical binding: {1}", {E, P});
      // Unwrap syntax closures.
      P = Context.RebuildLiteral(P);
      E = Context.RebuildLiteral(E);
    }
    if (equal(P, E)) {
      return next(Op);
    } else {
      Context.setLoc(E.getSourceLocation());
      return patternFail(Op, "expecting literal: {1}", {E, P});
    }
  }

  BlockItrTy Visit(MatchPairOp Op) {
    heavy::Value E = getValue(Op.getInput());
    if (auto* Pair = dyn_cast<heavy::Pair>(E)) {
      setValue(Op.getCar(), Pair->Car);
      setValue(Op.getCdr(), Pair->Cdr);
      return next(Op);
    }
    Context.setLoc(E.getSourceLocation());
    return patternFail(Op, "expecting pair", E);
  }

  BlockItrTy Visit(MatchTailOp Op) {
    // Here we include the last cdr in the length
    // of a list proper or improper.
    heavy::Value E = getValue(Op.getInput());
    uint32_t TargetLen = Op.getLength();
    assert(TargetLen >= 1 && "expecting positive length");
    uint32_t TotalLen = 1;
    heavy::Value Cur = E;
    while (auto* Pair = dyn_cast<heavy::Pair>(Cur)) {
      ++TotalLen;
      Cur = Pair->Cdr;
    }
    if (TotalLen < TargetLen)
      return patternFail(Op, "list length for subpattern does not match",
                             {E, Int(TargetLen), Int(TotalLen)});
    Cur = E;
    for (uint32_t i = 0; i < TotalLen - TargetLen; i++)
      Cur = cast<heavy::Pair>(Cur)->Cdr;
    setValue(Op.getTail(), Cur);
    return next(Op);
  }

  BlockItrTy Visit(MatchArgsOp Op) {
    ValueRefs CallArgs = Context.getCallArgs();

    // Match the results against the call arguments.
    mlir::ValueRange Results = Op.getResults();

    if (Results.empty() && CallArgs.empty())
      return next(Op);

    bool IsValidArity = true;
    for (mlir::Value Result : Results) {
      if (isa<HeavyRestTy>(Result.getType())) {
        // HeavyRestTy matches any remaining amount of CallArgs.
        // The value should only be used as an argument to ApplyOp.
        Value RestList = Context.CreateList(CallArgs);
        setValue(Result, RestList);
        return next(Op);
      }
      if (CallArgs.empty()) {
        IsValidArity = false;
        break;
      }

      // Type check would go here.
      setValue(Result, CallArgs.front());
      CallArgs = CallArgs.drop_front();
    }

    if (!CallArgs.empty())
      IsValidArity = false;

    if (!IsValidArity)
      return patternFail(Op, "invalid arity", {Context.getCallee()});
    else
      return next(Op);
  }

  BlockItrTy Visit(ExpandPacksOp Op) {
    heavy::SourceLocation Loc = getSourceLocation(Op.getLoc());
    setValue(Op.getResult(), getValue(Op.getCdr()));
    llvm::SmallVector<heavy::Value, 4> Packs(Op.getPacks().size());
    mlir::ValueRange PackInputs = Op.getPacks();
    auto BlockArgs = Op.getBody().getArguments();
    assert(Packs.size() >= 1 && "should have some packs");
    for (unsigned i = 0; i < Packs.size(); i++)
      Packs[i] = getValue(PackInputs[i]);

    // Recall that each pack is a list in reverse order.
    while (isa<heavy::Pair>(Packs.front())) {
      // Set each block argument to the cdr of each pack.
      auto Scope = ValueMapScope(ValueMap);
      for (unsigned i = 0; i < Packs.size(); i++) {
        auto* Pair = dyn_cast<heavy::Pair>(Packs[i]);
        if (!Pair)
          return SetError(Loc, "expansion packs should have equal length");
        setValue(BlockArgs[i], Pair->Car);
        Packs[i] = Pair->Cdr;
      }
      BlockItrTy Itr = Op.getBody().front().begin();
      while (Itr != BlockItrTy())
        Itr = Visit(&*Itr);
    }

    for (unsigned i = 0; i < Packs.size(); i++) {
      if (!isa<Empty>(Packs[i]))
        return SetError(Loc, "expansion packs should have equal length");
    }

    return next(Op);
  }

  BlockItrTy Visit(SubpatternOp Op) {
    heavy::Value E = getValue(Op.getInput());
    heavy::Value Tail = getValue(Op.getTail());

    // Match the empty list.
    if (isa<heavy::Empty>(E)) {
      for (mlir::Value Pack : Op.getPacks())
        setValue(Pack, Empty());
      return next(Op);
    }

    // Initialize result packs for storage as reverse ordered lists.
    for (mlir::Value PackResult : Op.getPacks())
      setValue(PackResult, Empty());

    assert(Op.getBody().getNumArguments() == 1
        && "body should have single argument");
    mlir::Value BodyArg = Op.getBody().getArgument(0);
    // Visit the subpattern body for each element in E
    // stopping when we find tail or a non-pair object.
    // Each "pack" should be a list.
    while (auto* Pair = dyn_cast<heavy::Pair>(E)) {
      if (E == Tail)
        break;
      auto Scope = ValueMapScope(ValueMap);
      BlockItrTy Itr = Op.getBody().front().begin();
      setValue(BodyArg, Pair->Car);
      while (Itr != BlockItrTy() && Itr != BlockItrTy(Op))
        Itr = Visit(&*Itr);
      // Check subpattern failure.
      if (Itr == BlockItrTy(Op))
        break;
      E = Pair->Cdr;
    }

    // Fail if E still has junk that is not Tail and
    // did not get gobbled up by the subpattern.
    if (E != Tail)
      return patternFail(Op, "unexpected elements after subpattern", {E});

    return next(Op);
  }

  BlockItrTy Visit(ResolveOp Op) {
    if (auto ParentOp = dyn_cast<SubpatternOp>(Op->getParentOp())) {
      // We are at the terminator of a subpattern body region.
      assert(ParentOp.getPacks().size() ==
             Op.getArgs().size() &&
             "expecting value ranges of equal size");
      mlir::ValueRange ResolveArgs = Op.getArgs();
      mlir::ResultRange MResults = ParentOp.getPacks();
      // Construct each pack as a reversed ordered list.
      for (unsigned i = 0; i < ResolveArgs.size(); i++) {
        Value Pack = Context.CreatePair(getValue(ResolveArgs[i]),
                                        getValue(MResults[i]));
        setValueParentScope(MResults[i], Pack);
      }
      return BlockItrTy();
    }

    auto ExpandPacksOp = cast<heavy::ExpandPacksOp>(Op->getParentOp());
    assert(Op.getArgs().size() == 1 && "expecting single result");
    heavy::Value CurrentResult = getValue(Op.getArgs().front());
    heavy::Value Result = Context.CreatePair(CurrentResult,
                                      getValue(ExpandPacksOp.getResult()));
    setValueParentScope(ExpandPacksOp.getResult(), Result);
    return BlockItrTy();
  }

  BlockItrTy Visit(MatchIdOp Op) {
    heavy::Value P = getValue(Op.getVal());
    heavy::Value E = getValue(Op.getInput());
    if (P == E) {
      return next(Op);
    }
    return patternFail(Op, "identifier does not match", {E, P});
  }

  BlockItrTy Visit(SyntaxClosureOp Op) {
    // Create a SyntaxClosure with the provided env argument.
    heavy::Value Input = getValue(Op.getInput());
    heavy::Value Env = getValue(Op.getEnv());
    Value SC = Context.CreateSyntaxClosure(Context.getLoc(), Input, Env);
    setValue(Op.getResult(), SC);

    return next(Op);
  }

  BlockItrTy Visit(RenameOp Op) {
    heavy::Value Capture = getValue(Op.getCapture());
    heavy::Symbol* Id = Context.CreateSymbol(Op.getId());
    heavy::Binding* B = Context.CreateBinding(Id, Capture);
    setValue(Op.getResult(), B);

    return next(Op);
  }

  BlockItrTy Visit(RenameGlobalOp Op) {
    heavy::SourceLocation Loc = Context.getLoc();
    heavy::Value ExtName = Context.CreateExternName(Loc, Op.getSym());
    heavy::Symbol* Id = Context.CreateSymbol(Op.getId());
    heavy::Binding* B = Context.CreateBinding(Id, ExtName);
    setValue(Op.getResult(), B);

    return next(Op);
  }

  BlockItrTy Visit(OpGenOp Op) {
    heavy::OpGen* OpGen = Context.OpGen;  // For debug only.
    heavy::Value Input = getValue(Op.getInput());
    mlir::Value Result = Context.OpGen->Visit(Input);
    heavy::Value Output = heavy::OpGen::fromValue(Result);
    assert(OpGen == Context.OpGen && "OpGen visit should not unwind itself");
    if (!Context.OpGen || !Context.OpGen->CheckError())
      Context.Cont(Output);
    return BlockItrTy();
  }

  BlockItrTy Visit(SourceLocOp Op) {
    heavy::SourceLocation Loc = getSourceLocation(Op.getLoc());
    heavy::Value V = Context.CreateSourceValue(Loc);
    setValue(Op.getResult(), V);
    return next(Op);
  }
};

void OpEvalDeleter::operator()(OpEvalImpl* Ptr) const {
  delete Ptr;
}

namespace builtins {
void op_eval(Context& C, ValueRefs Args) {
  if (Args.size() != 1) {
    return C.RaiseError("invalid arity");
  }
  mlir::Operation* Op = dyn_cast<mlir::Operation>(Args[0]);
  if (!Op) {
    return C.RaiseError("expecting operation");
  }

  if (!C.OpEval) {
    // Still easier than extern template specialization of std::default_delete
    C.OpEval = OpEvalPtr(new OpEvalImpl(C), OpEvalDeleter());
  }

  C.OpEval->Eval(Op);
}

}  // end namespace builtins
}  // end namespace heavy
